import arrow from "./arrow.svg";
import {
  LandingPage,
  Heading,
  Arrow,
  Fade,
} from "./landing.style";
import {
  ScrollLanding,
  ScrollUp,
} from "./scroll.style"
import { Page } from "./webpage.style";

function App() {
  return (
    <>
    <Fade>
      <div id="landing">
        <ScrollLanding href="#page">
          <LandingPage className="landing-page" id="landing">
            <Heading> e g a &nbsp; c h e u n g </Heading>
            <Arrow tabIndex={-1} src={arrow} alt="arrow" />
          </LandingPage>
        </ScrollLanding>
      </div>
      </Fade>
      <div id="page">
      <Page>
        <ScrollUp href="#landing"></ScrollUp>
      </Page>

      </div>
    </>
  );
}

export default App;
